UPDATE problems SET starter_code = $sc${"javascript": "function twoSum(nums, target) {\n  const map = {};\n  for (let i = 0; i < nums.length; i++) {\n    const complement = target - nums[i];\n    if (map[complement] !== undefined) {\n      return [map[complement], i];\n    }\n    map[nums[i]] = i;\n  }\n}", "typescript": "function twoSum(nums: number[], target: number): number[] {\n  const map: Record<number, number> = {};\n  for (let i = 0; i < nums.length; i++) {\n    const complement = target - nums[i];\n    if (/* complement in map */) {\n      return [map[complement], i];\n    }\n    map[nums[i]] = i;\n  }\n  return [];\n}", "python": "def two_sum(nums, target):\n    seen = {}\n    for i, num in enumerate(nums):\n        complement = target - num\n        if complement in seen:\n            return [seen[complement], i]\n        seen[num] = i", "cpp": "#include <vector>\n#include <unordered_map>\nusing namespace std;\nvector<int> twoSum(vector<int>& nums, int target) {\n    unordered_map<int,int> seen;\n    for (int i = 0; i < (int)nums.size(); i++) {\n        int complement = target - nums[i];\n        if (/* complement is in seen */) {\n            return {seen[complement], i};\n        }\n        seen[nums[i]] = i;\n    }\n    return {};\n}", "c": "#include <stdio.h>\n#include <stdlib.h>\nint main() {\n    /* brute force: check every pair */\n    int nums[1000], n = 0, target;\n    /* parse input then: */\n    for (int i = 0; i < n; i++)\n        for (int j = i + 1; j < n; j++)\n            if (/* nums[i] + nums[j] == target */)\n                printf(\"[%d,%d]\\n\", i, j);\n    return 0;\n}", "csharp": "using System;\nusing System.Collections.Generic;\nclass Solution {\n    static void Main() {\n        var map = new Dictionary<int,int>();\n        /* parse input then loop: */\n        /* if (map.ContainsKey(complement)) ... */\n    }\n}"}$sc$::jsonb WHERE slug = 'two-sum';
UPDATE problems SET starter_code = $sc${"javascript": "function isPalindrome(s) {\n  const clean = s.toLowerCase().replace(/[^a-z0-9]/g, \"\");\n  let left = 0, right = clean.length - 1;\n  while (left < right) {\n    if (/* characters at left and right don't match */) return false;\n    left++;\n    right--;\n  }\n  return true;\n}", "typescript": "function isPalindrome(s: string): boolean {\n  const clean = s.toLowerCase().replace(/[^a-z0-9]/g, \"\");\n  let left = 0, right = clean.length - 1;\n  while (left < right) {\n    if (/* characters at left and right don't match */) return false;\n    left++;\n    right--;\n  }\n  return true;\n}", "python": "def is_palindrome(s: str) -> bool:\n    clean = [c.lower() for c in s if c.isalnum()]\n    left, right = 0, len(clean) - 1\n    while left < right:\n        if clean[left] != clean[right]:\n            return False\n        left += 1\n        right -= 1\n    return True", "cpp": "#include <string>\n#include <cctype>\nbool isPalindrome(std::string s) {\n    int l = 0, r = s.size() - 1;\n    while (l < r) {\n        while (l < r && !isalnum(s[l])) l++;\n        while (l < r && !isalnum(s[r])) r--;\n        if (/* tolower(s[l]) != tolower(s[r]) */) return false;\n        l++; r--;\n    }\n    return true;\n}"}$sc$::jsonb WHERE slug = 'valid-palindrome';
UPDATE problems SET starter_code = $sc${"javascript": "function fizzBuzz(n) {\n  const result = [];\n  for (let i = 1; i <= n; i++) {\n    if (/* divisible by both 3 and 5 */) result.push(\"FizzBuzz\");\n    else if (/* divisible by 3 */) result.push(\"Fizz\");\n    else if (/* divisible by 5 */) result.push(\"Buzz\");\n    else result.push(String(i));\n  }\n  return result;\n}", "typescript": "function fizzBuzz(n: number): string[] {\n  const result: string[] = [];\n  for (let i = 1; i <= n; i++) {\n    if (/* divisible by both 3 and 5 */) result.push(\"FizzBuzz\");\n    else if (/* divisible by 3 */) result.push(\"Fizz\");\n    else if (/* divisible by 5 */) result.push(\"Buzz\");\n    else result.push(String(i));\n  }\n  return result;\n}", "python": "def fizz_buzz(n):\n    result = []\n    for i in range(1, n + 1):\n        if i % 15 == 0:\n            result.append(\"FizzBuzz\")\n        elif i % 3 == 0:\n            result.append(\"Fizz\")\n        elif i % 5 == 0:\n            result.append(\"Buzz\")\n        else:\n            result.append(str(i))\n    return result", "cpp": "#include <iostream>\nusing namespace std;\nint main() {\n    int n; cin >> n;\n    for (int i = 1; i <= n; i++) {\n        if (/* i % 15 == 0 */) cout << \"FizzBuzz\";\n        else if (/* i % 3 == 0 */) cout << \"Fizz\";\n        else if (/* i % 5 == 0 */) cout << \"Buzz\";\n        else cout << i;\n        if (i < n) cout << \",\";\n    }\n    cout << endl;\n}", "c": "#include <stdio.h>\nint main() {\n    int n; scanf(\"%d\", &n);\n    for (int i = 1; i <= n; i++) {\n        if (/* i % 15 == 0 */) printf(\"FizzBuzz\");\n        else if (/* i % 3 == 0 */) printf(\"Fizz\");\n        else if (/* i % 5 == 0 */) printf(\"Buzz\");\n        else printf(\"%d\", i);\n        if (i < n) printf(\",\");\n    }\n    printf(\"\\n\");\n}", "csharp": "using System;\nusing System.Collections.Generic;\nclass Solution {\n    static void Main() {\n        int n = int.Parse(Console.ReadLine());\n        var parts = new List<string>();\n        for (int i = 1; i <= n; i++) {\n            if (/* i % 15 == 0 */) parts.Add(\"FizzBuzz\");\n            else if (/* i % 3 == 0 */) parts.Add(\"Fizz\");\n            else if (/* i % 5 == 0 */) parts.Add(\"Buzz\");\n            else parts.Add(i.ToString());\n        }\n        Console.WriteLine(\"[\" + string.Join(\",\", parts.ConvertAll(p => \"\\\"\" + p + \"\\\"\")) + \"]\");\n    }\n}"}$sc$::jsonb WHERE slug = 'fizzbuzz';
UPDATE problems SET starter_code = $sc${"javascript": "function search(nums, target) {\n  let left = 0, right = nums.length - 1;\n  while (left <= right) {\n    const mid = Math.floor((left + right) / 2);\n    if (nums[mid] === target) return mid;\n    else if (/* target is in the right half */) left = mid + 1;\n    else right = mid - 1;\n  }\n  return -1;\n}", "typescript": "function search(nums: number[], target: number): number {\n  let left = 0, right = nums.length - 1;\n  while (left <= right) {\n    const mid = Math.floor((left + right) / 2);\n    if (nums[mid] === target) return mid;\n    else if (/* target is in the right half */) left = mid + 1;\n    else right = mid - 1;\n  }\n  return -1;\n}", "python": "def search(nums, target):\n    left, right = 0, len(nums) - 1\n    while left <= right:\n        mid = (left + right) // 2\n        if nums[mid] == target:\n            return mid\n        elif /* target is in the right half */:\n            left = mid + 1\n        else:\n            right = mid - 1\n    return -1", "cpp": "#include <vector>\nusing namespace std;\nint search(vector<int>& nums, int target) {\n    int left = 0, right = nums.size() - 1;\n    while (left <= right) {\n        int mid = left + (right - left) / 2;\n        if (nums[mid] == target) return mid;\n        else if (/* target > nums[mid] */) left = mid + 1;\n        else right = mid - 1;\n    }\n    return -1;\n}"}$sc$::jsonb WHERE slug = 'binary-search';
